// ─── Rarity system ───────────────────────────────────────────────────────────

export type RarityKey = "C" | "CC" | "R" | "RR" | "RRR";

export const RARITY_CONFIG: Record<RarityKey, {
  label: string;
  fullLabel: string;
  coverColor: string;
  badgeBg: string;
  badgeColor: string;
  shine: boolean;
}> = {
  C:   { label: "C",   fullLabel: "Common",      coverColor: "#6B7280", badgeBg: "#F3F4F6", badgeColor: "#374151", shine: false },
  CC:  { label: "CC",  fullLabel: "Uncommon",    coverColor: "#2563EB", badgeBg: "#DBEAFE", badgeColor: "#1D4ED8", shine: false },
  R:   { label: "R",   fullLabel: "Rare",        coverColor: "#7C3AED", badgeBg: "#EDE9FE", badgeColor: "#6D28D9", shine: false },
  RR:  { label: "RR",  fullLabel: "Double Rare", coverColor: "#B45309", badgeBg: "#FEF3C7", badgeColor: "#92400E", shine: true  },
  RRR: { label: "RRR", fullLabel: "Ultra Rare",  coverColor: "#991B1B", badgeBg: "#FEE2E2", badgeColor: "#7F1D1D", shine: true  },
};

export function getRarityKey(persona: Persona): RarityKey {
  if (persona.rarityOverride) return persona.rarityOverride;
  const avg = persona.personalityDimensions.reduce((s, d) => s + d.value, 0) / persona.personalityDimensions.length;
  if (avg >= 94) return "RRR";
  if (avg >= 88) return "RR";
  if (avg >= 80) return "R";
  if (avg >= 70) return "CC";
  return "C";
}

export function getRarity(persona: Persona) {
  const key = getRarityKey(persona);
  return { key, ...RARITY_CONFIG[key] };
}

