// ─── Related personas ─────────────────────────────────────────────────────────

export function getRelatedPersonas(personaId: string): Array<{ persona: Persona; relationship: Relationship }> {
  const current = personas.find((p) => p.id === personaId);
  if (!current) return [];
  return current.relationships
    .map((rel) => {
      const related = personas.find((p) => p.id === rel.personaId);
      if (!related) return null;
      return { persona: related, relationship: rel };
    })
    .filter((item): item is { persona: Persona; relationship: Relationship } => item !== null);
}

export function getPersonaById(id: string): Persona | undefined {
  return personas.find((p) => p.id === id);
}

